package co.edu.elecciones.controller; import co.edu.elecciones.commons.dto.ApiResponse; import co.edu.elecciones.domain.*; import co.edu.elecciones.dto.Requests.*; import co.edu.elecciones.repository.*; import co.edu.elecciones.service.AuditService; import jakarta.servlet.http.HttpServletRequest; import org.apache.commons.csv.*; import org.springframework.web.bind.annotation.*; import org.springframework.web.multipart.MultipartFile; import java.io.*; import java.nio.charset.StandardCharsets; import java.util.*;
@RestController @RequestMapping("/api/v1/encuestas") public class EncuestasController { private final PollRepository repo; private final CandidateRepository candidates; private final AuditService audit; public EncuestasController(PollRepository r,CandidateRepository c,AuditService a){repo=r;candidates=c;audit=a;} @GetMapping public ApiResponse<List<Poll>> all(){return ApiResponse.ok("OK",repo.findAll());} @PostMapping public ApiResponse<Poll> create(@RequestBody PollRequest req,HttpServletRequest http){ Poll p=new Poll(); map(p,req); var s=repo.save(p); audit.log("CREATE","Poll",s.id,"Creación",http); return ApiResponse.ok("Creada",s);} @PutMapping("/{id}") public ApiResponse<Poll> update(@PathVariable Long id,@RequestBody PollRequest req,HttpServletRequest http){var p=repo.findById(id).orElseThrow(); p.results.clear(); map(p,req); var s=repo.save(p); audit.log("UPDATE","Poll",s.id,"Actualización",http); return ApiResponse.ok("Actualizada",s);} @DeleteMapping("/{id}") public ApiResponse<Void> delete(@PathVariable Long id,HttpServletRequest http){repo.deleteById(id); audit.log("DELETE","Poll",id,"Eliminación",http); return ApiResponse.ok("Eliminada",null);} @PostMapping("/import-csv") public ApiResponse<Integer> csv(@RequestParam MultipartFile file,HttpServletRequest http)throws Exception{ int n=0; try(var r=new InputStreamReader(file.getInputStream(),StandardCharsets.UTF_8)){ for(CSVRecord rec:CSVFormat.DEFAULT.withFirstRecordAsHeader().parse(r)){ Poll p=new Poll(); p.source=rec.get("source"); p.date=java.time.LocalDate.parse(rec.get("date")); p.sampleSize=Integer.parseInt(rec.get("sampleSize")); p.marginError=Double.parseDouble(rec.get("marginError")); p.methodology=rec.get("methodology"); repo.save(p); n++; }} audit.log("IMPORT","Poll",null,"CSV encuestas: "+n,http); return ApiResponse.ok("Importadas",n);} private void map(Poll p,PollRequest r){p.source=r.source();p.date=r.date();p.sampleSize=r.sampleSize();p.marginError=r.marginError();p.methodology=r.methodology(); if(r.results()!=null) for(var rr:r.results()){ PollResult pr=new PollResult(); pr.poll=p; pr.candidate=candidates.findById(rr.candidateId()).orElseThrow(); pr.percentage=rr.percentage(); p.results.add(pr); }} }
